document.addEventListener('DOMContentLoaded', () => {
    const listingGrid = document.querySelector('.listing-grid');
    const searchInput = document.querySelector('.search-input');
    const categoryBtns = document.querySelectorAll('.category-btn');

    // Mock data for initial demonstration until real files are created
    // In a real environment, this list would be generated by a server or build script
    let listings = [];

    async function loadListings() {
        try {
            // We'll try to fetch a manifest file. If not found, we'll use an empty list or mock.
            const response = await fetch('listings/manifest.json');
            if (response.ok) {
                listings = await response.json();
            } else {
                console.warn('Listing manifest not found. Please run the generator.');
            }
            renderListings(listings);
        } catch (error) {
            console.error('Error loading listings:', error);
        }
    }

    function renderListings(items) {
        if (!listingGrid) return;
        
        listingGrid.innerHTML = items.length ? '' : '<p class="text-center w-full col-span-full py-20 text-muted">No listings found matching your criteria.</p>';
        
        items.forEach((item, index) => {
            const card = document.createElement('a');
            card.href = `listings/${item.filename}`;
            card.className = 'business-card';
            card.style.animationDelay = `${index * 0.1}s`;
            
            card.innerHTML = `
                <div class="business-logo">
                    <img src="${item.logo || 'https://via.placeholder.com/64'}" alt="${item.name}">
                </div>
                <h3 class="business-name">${item.name}</h3>
                <p class="business-desc">${item.description}</p>
                <div class="business-meta">
                    <span class="business-category">${item.category}</span>
                    <span class="view-btn">
                        View Listing
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
                    </span>
                </div>
            `;
            listingGrid.appendChild(card);
        });
    }

    // Search functionality
    if (searchInput) {
        searchInput.addEventListener('input', (e) => {
            const term = e.target.value.toLowerCase();
            const filtered = listings.filter(l => 
                l.name.toLowerCase().includes(term) || 
                l.description.toLowerCase().includes(term) ||
                l.category.toLowerCase().includes(term)
            );
            renderListings(filtered);
        });
    }

    // Category filtering
    categoryBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            categoryBtns.forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            
            const category = btn.textContent.trim();
            if (category === 'All') {
                renderListings(listings);
            } else {
                const filtered = listings.filter(l => l.category === category);
                renderListings(filtered);
            }
        });
    });

    loadListings();
});
